import { createReactMicroApp } from '@tuvix.js/react';
import { useState } from 'react';
function MultiStepForm() {
  const [step, setStep] = useState(0);
  const steps = ['Personal', 'Account', 'Review'];
  return (
    <div style={{ maxWidth: 480, margin: '40px auto', padding: '24px', border: '1px solid #e5e5e5', borderRadius: '8px' }}>
      <div style={{ display: 'flex', gap: '8px', marginBottom: '24px' }}>
        {steps.map((s, i) => (
          <div key={s} style={{ flex: 1, height: '4px', background: i <= step ? '#111' : '#e5e5e5', borderRadius: '2px' }} />
        ))}
      </div>
      <h3>{steps[step]}</h3>
      <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: '24px' }}>
        {step > 0 && <button onClick={() => setStep(step-1)} style={{ padding: '8px 16px', border: '1px solid #333', background: 'transparent', borderRadius: '4px', cursor: 'pointer' }}>Back</button>}
        {step < steps.length - 1 && <button onClick={() => setStep(step+1)} style={{ marginLeft: 'auto', padding: '8px 16px', background: '#111', color: '#fff', border: 'none', borderRadius: '4px', cursor: 'pointer' }}>Next</button>}
        {step === steps.length - 1 && <button style={{ marginLeft: 'auto', padding: '8px 16px', background: '#22c55e', color: '#fff', border: 'none', borderRadius: '4px', cursor: 'pointer' }}>Submit</button>}
      </div>
    </div>
  );
}
export default createReactMicroApp({ component: MultiStepForm });

